    private final List<String> erroresSintacticos = new ArrayList<>();
    private final List<String> erroresSemanticos = new ArrayList<>();

    private final SymbolTableManager tablaSimbolos = new SymbolTableManager();

    private SymbolInfo currentFunction = null;
    private int blockCounter = 0;

    public List<String> getErroresSintacticos() {
        return erroresSintacticos;
    }

    public List<String> getErroresSemanticos() {
        return erroresSemanticos;
    }

    public boolean tieneErrores() {
        return !erroresSintacticos.isEmpty() || !erroresSemanticos.isEmpty();
    }

    public boolean tieneErroresSemanticos() {
        return !erroresSemanticos.isEmpty();
    }

    public SymbolTableManager getTablaSimbolos() {
        return tablaSimbolos;
    }

    private String nombreToken(Symbol tok) {
        if (tok == null) return "EOF";
        try {
            return sym.terminalNames[tok.sym];
        } catch (Exception e) {
            return "SYM(" + tok.sym + ")";
        }
    }

    private String lexemaToken(Symbol tok) {
        if (tok == null) return "<EOF>";
        return tok.value != null ? tok.value.toString() : nombreToken(tok);
    }

    private void errorSemantico(String mensaje) {
        erroresSemanticos.add(mensaje);
    }

    private void declararFuncion(String name, DataType returnType, int line, int col, boolean isMain) {
        SymbolInfo info = new SymbolInfo(
                name,
                isMain ? SymbolKind.MAIN : SymbolKind.FUNCTION,
                isMain ? DataType.EMPTY : returnType,
                line,
                col,
                "global",
                0
        );

        boolean inserted = tablaSimbolos.insertIntoGlobal(info);
        if (!inserted) {
            errorSemantico(
                "Error semántico: redeclaración de función/procedimiento '" + name +
                "' en línea " + line + ", columna " + col
            );
            currentFunction = tablaSimbolos.lookupGlobal(name);
        } else {
            currentFunction = info;
        }

        tablaSimbolos.enterScope(name);
    }

    private void cerrarFuncion() {
        currentFunction = null;
        tablaSimbolos.exitScope();
    }

    private void registrarParametros(ArrayList params) {
        if (params == null) return;

        for (Object obj : params) {
            ParameterInfo p = (ParameterInfo) obj;

            SymbolInfo s = new SymbolInfo(
                    p.getName(),
                    SymbolKind.PARAMETER,
                    p.getType(),
                    p.getLine(),
                    p.getColumn(),
                    tablaSimbolos.currentScope().getName(),
                    tablaSimbolos.currentScope().getLevel()
            );
            s.setInitialized(true);

            boolean inserted = tablaSimbolos.insert(s);
            if (!inserted) {
                errorSemantico(
                    "Error semántico: parámetro redeclarado '" + p.getName() +
                    "' en línea " + p.getLine() + ", columna " + p.getColumn()
                );
            }

            if (currentFunction != null) {
                currentFunction.addParameter(p.getName(), p.getType());
            }
        }
    }

    private void declararIdentificador(String name, DataType type, DeclTailInfo tail, int line, int col) {
        SymbolKind kind = tail.isArray() ? SymbolKind.ARRAY : SymbolKind.VARIABLE;

        SymbolInfo info = new SymbolInfo(
                name,
                kind,
                type,
                line,
                col,
                tablaSimbolos.currentScope().getName(),
                tablaSimbolos.currentScope().getLevel()
        );

        info.setInitialized(tail.isInitialized());

        if (tail.isArray()) {
            info.setDimensions(tail.getDim1(), tail.getDim2());
        }

        boolean inserted = tablaSimbolos.insert(info);
        if (!inserted) {
            errorSemantico(
                "Error semántico: identificador redeclarado '" + name +
                "' en línea " + line + ", columna " + col +
                " dentro del scope '" + tablaSimbolos.currentScope().getName() + "'"
            );
        }
    }

    private void usarVariable(String name, int line, int col) {
        SymbolInfo s = tablaSimbolos.lookup(name);

        if (s == null) {
            errorSemantico(
                "Error semántico: identificador no declarado '" + name +
                "' en línea " + line + ", columna " + col
            );
            return;
        }

        if (s.getKind() == SymbolKind.FUNCTION || s.getKind() == SymbolKind.MAIN) {
            errorSemantico(
                "Error semántico: '" + name +
                "' es una función/procedimiento y no una variable en línea " + line + ", columna " + col
            );
            return;
        }

        if (s.getKind() == SymbolKind.ARRAY) {
            errorSemantico(
                "Error semántico: el arreglo '" + name +
                "' requiere índices en línea " + line + ", columna " + col
            );
            return;
        }

        s.setUsed(true);
    }

    private void usarArreglo(String name, int line, int col) {
        SymbolInfo s = tablaSimbolos.lookup(name);

        if (s == null) {
            errorSemantico(
                "Error semántico: arreglo no declarado '" + name +
                "' en línea " + line + ", columna " + col
            );
            return;
        }

        if (s.getKind() != SymbolKind.ARRAY) {
            errorSemantico(
                "Error semántico: '" + name +
                "' no es un arreglo en línea " + line + ", columna " + col
            );
            return;
        }

        s.setUsed(true);
    }

    private void usarFuncion(String name, int line, int col) {
        SymbolInfo s = tablaSimbolos.lookupGlobal(name);

        if (s == null) {
            errorSemantico(
                "Error semántico: función/procedimiento no declarado '" + name +
                "' en línea " + line + ", columna " + col
            );
            return;
        }

        if (s.getKind() != SymbolKind.FUNCTION && s.getKind() != SymbolKind.MAIN) {
            errorSemantico(
                "Error semántico: '" + name +
                "' no es una función/procedimiento en línea " + line + ", columna " + col
            );
            return;
        }

        s.setUsed(true);
    }

    private void entrarBloqueAnonimo() {
        blockCounter++;
        tablaSimbolos.enterScope("block_" + blockCounter);
    }

    private void salirScope() {
        tablaSimbolos.exitScope();
    }

    @Override
    public void syntax_error(Symbol cur_token) {
        String mensaje =
                "Error sintáctico en línea " + (cur_token != null ? cur_token.left : -1) +
                ", columna " + (cur_token != null ? cur_token.right : -1) +
                ". Token encontrado: " + nombreToken(cur_token) +
                " (" + lexemaToken(cur_token) + ")";
        erroresSintacticos.add(mensaje);
    }

    @Override
    public void unrecovered_syntax_error(Symbol cur_token) throws Exception {
        String mensaje =
                "Recuperación fallida en línea " + (cur_token != null ? cur_token.left : -1) +
                ", columna " + (cur_token != null ? cur_token.right : -1) +
                ". No fue posible continuar desde: " + nombreToken(cur_token) +
                " (" + lexemaToken(cur_token) + ")";
        erroresSintacticos.add(mensaje);
        done_parsing();
    }


